package com.example.mfa.service;

import com.example.mfa.entity.AppUser;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class UserService implements UserDetailsService {

    private final UserRepository userRepository;
    private final PasswordEncoder encoder;

    public UserService(UserRepository userRepository, PasswordEncoder encoder) {
        this.userRepository = userRepository;
        this.encoder = encoder;
    }

    @Transactional
    public AppUser register(String username, String password) {
        userRepository.findByUsername(username).ifPresent(u -> {
            throw new IllegalArgumentException("username already exists");
        });
        AppUser u = new AppUser();
        u.setUsername(username);
        u.setPasswordHash(encoder.encode(password));
        return userRepository.save(u);
    }

    public AppUser getByUsername(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new UsernameNotFoundException("user not found"));
    }

    public boolean passwordMatches(AppUser user, String rawPassword) {
        return encoder.matches(rawPassword, user.getPasswordHash());
    }

    @Override
    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
        AppUser u = getByUsername(username);
        List<GrantedAuthority> authorities = List.of(new SimpleGrantedAuthority("ROLE_USER"));
        return new org.springframework.security.core.userdetails.User(u.getUsername(), u.getPasswordHash(), authorities);
    }
}
package com.example.mfa.service;

import com.example.mfa.entity.AppUser;
import com.example.mfa.entity.BackupCode;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.repo.UserRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Service
public class BackupCodeService {

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom random = new SecureRandom();
    private final int codeCount;
    private final int codeBytes;

    public BackupCodeService(
            BackupCodeRepository backupCodeRepository,
            UserRepository userRepository,
            PasswordEncoder passwordEncoder,
            @Value("${app.mfa.backup.codeCount:10}") int codeCount,
            @Value("${app.mfa.backup.codeBytes:9}") int codeBytes
    ) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.codeCount = codeCount;
        this.codeBytes = codeBytes;
    }

    public static String normalize(String code) {
        if (code == null) return null;
        return code.replaceAll("[\\s-]", "").trim().toUpperCase();
    }

    private String generateOneCode() {
        byte[] b = new byte[codeBytes];
        random.nextBytes(b);
        String s = Base64.getUrlEncoder().withoutPadding().encodeToString(b).toUpperCase();
        if (s.length() > 12) s = s.substring(0, 12);
        return s;
    }

    @Transactional
    public List<String> generateAndStoreNewCodes(AppUser user) {
        backupCodeRepository.deleteByUser(user);

        List<String> plain = new ArrayList<>(codeCount);
        List<BackupCode> entities = new ArrayList<>(codeCount);

        for (int i = 0; i < codeCount; i++) {
            String c = generateOneCode();
            String normalized = normalize(c);
            plain.add(formatForDisplay(normalized));

            BackupCode bc = new BackupCode();
            bc.setUser(user);
            bc.setCodeHash(passwordEncoder.encode(normalized));
            bc.setUsed(false);
            bc.setCreatedAt(Instant.now());
            entities.add(bc);
        }

        backupCodeRepository.saveAll(entities);
        return plain;
    }

    public static String formatForDisplay(String normalized) {
        if (normalized == null) return null;
        if (normalized.length() <= 4) return normalized;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < normalized.length(); i++) {
            if (i > 0 && i % 4 == 0) sb.append('-');
            sb.append(normalized.charAt(i));
        }
        return sb.toString();
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String presentedCode) {
        String normalized = normalize(presentedCode);
        if (normalized == null || normalized.isEmpty()) return false;

        List<BackupCode> codes = backupCodeRepository.findByUserAndUsedFalse(user);
        for (BackupCode c : codes) {
            if (passwordEncoder.matches(normalized, c.getCodeHash())) {
                c.setUsed(true);
                c.setUsedAt(Instant.now());
                backupCodeRepository.save(c);
                return true;
            }
        }
        return false;
    }

    @Transactional
    public AppUser setMfaEnabled(AppUser user, boolean enabled) {
        user.setMfaEnabled(enabled);
        return userRepository.save(user);
    }
}
package com.example.mfa.service;

import com.example.mfa.security.JwtService;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Date;
import java.util.Map;

@Service
public class MfaTokenService {

    private final SecretKey key;
    private final long ttlSeconds;

    public MfaTokenService(
            @Value("${app.mfa.jwt.secret}") String secret,
            @Value("${app.mfa.jwt.ttlSeconds:300}") long ttlSeconds
    ) {
        this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
        this.ttlSeconds = ttlSeconds;
    }

    public String generateMfaToken(String username) {
        Instant now = Instant.now();
        return Jwts.builder()
                .subject(username)
                .claims(Map.of("type", "MFA"))
                .issuedAt(Date.from(now))
                .expiration(Date.from(now.plusSeconds(ttlSeconds)))
                .signWith(key)
                .compact();
    }

    public String extractUsernameIfValidMfaToken(String token) {
        try {
            Claims c = Jwts.parser().verifyWith(key).build().parseSignedClaims(token).getPayload();
            Object type = c.get("type");
            if (type == null || !"MFA".equals(type.toString())) return null;
            if (c.getExpiration() == null || !c.getExpiration().after(new Date())) return null;
            return c.getSubject();
        } catch (Exception e) {
            return null;
        }
    }
}
