package com.example.mfa.controller;

import com.example.mfa.dto.*;
import com.example.mfa.entity.AppUser;
import com.example.mfa.security.JwtService;
import com.example.mfa.service.BackupCodeService;
import com.example.mfa.service.MfaTokenService;
import com.example.mfa.service.TotpService;
import com.example.mfa.service.UserService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/auth")
public class AuthController {

    private final UserService userService;
    private final JwtService jwtService;
    private final MfaTokenService mfaTokenService;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;

    public AuthController(
            UserService userService,
            JwtService jwtService,
            MfaTokenService mfaTokenService,
            TotpService totpService,
            BackupCodeService backupCodeService
    ) {
        this.userService = userService;
        this.jwtService = jwtService;
        this.mfaTokenService = mfaTokenService;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@RequestBody RegisterRequest req) {
        if (req == null || req.username == null || req.password == null) {
            return ResponseEntity.badRequest().body(Map.of("error", "invalid request"));
        }
        AppUser u = userService.register(req.username.trim(), req.password);
        return ResponseEntity.status(HttpStatus.CREATED).body(Map.of("id", u.getId(), "username", u.getUsername()));
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@RequestBody LoginRequest req) {
        LoginResponse resp = new LoginResponse();
        AppUser u = userService.getByUsername(req.username);

        if (!userService.passwordMatches(u, req.password)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        if (u.isMfaEnabled()) {
            resp.status = "MFA_REQUIRED";
            resp.mfaToken = mfaTokenService.generateMfaToken(u.getUsername());
            return ResponseEntity.ok(resp);
        }

        resp.status = "OK";
        resp.accessToken = jwtService.generateToken(u.getUsername(), Map.of("amr", "pwd"));
        return ResponseEntity.ok(resp);
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<EnableMfaResponse> enableMfa(@AuthenticationPrincipal UserDetails principal) {
        AppUser u = userService.getByUsername(principal.getUsername());
        backupCodeService.setMfaEnabled(u, true);

        EnableMfaResponse resp = new EnableMfaResponse();
        resp.mfaEnabled = true;
        resp.backupCodes = backupCodeService.generateAndStoreNewCodes(u);
        return ResponseEntity.ok(resp);
    }

    @PostMapping("/mfa/backup/regenerate")
    public ResponseEntity<EnableMfaResponse> regenerateBackupCodes(@AuthenticationPrincipal UserDetails principal) {
        AppUser u = userService.getByUsername(principal.getUsername());
        if (!u.isMfaEnabled()) return ResponseEntity.status(HttpStatus.CONFLICT).build();

        EnableMfaResponse resp = new EnableMfaResponse();
        resp.mfaEnabled = true;
        resp.backupCodes = backupCodeService.generateAndStoreNewCodes(u);
        return ResponseEntity.ok(resp);
    }

    @PostMapping("/mfa/verify")
    public ResponseEntity<TokenResponse> verifyMfa(@RequestBody VerifyMfaRequest req) {
        String username = mfaTokenService.extractUsernameIfValidMfaToken(req.mfaToken);
        if (username == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();

        AppUser u = userService.getByUsername(username);
        if (!u.isMfaEnabled()) return ResponseEntity.status(HttpStatus.CONFLICT).build();

        if (!totpService.verifyCode(u.getTotpSecret(), req.totpCode)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        TokenResponse resp = new TokenResponse();
        resp.accessToken = jwtService.generateToken(u.getUsername(), Map.of("amr", "pwd+mfa"));
        return ResponseEntity.ok(resp);
    }

    @PostMapping("/mfa/backup/verify")
    public ResponseEntity<TokenResponse> verifyBackupCode(@RequestBody VerifyBackupCodeRequest req) {
        String username = mfaTokenService.extractUsernameIfValidMfaToken(req.mfaToken);
        if (username == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();

        AppUser u = userService.getByUsername(username);
        if (!u.isMfaEnabled()) return ResponseEntity.status(HttpStatus.CONFLICT).build();

        boolean ok = backupCodeService.consumeBackupCode(u, req.backupCode);
        if (!ok) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();

        TokenResponse resp = new TokenResponse();
        resp.accessToken = jwtService.generateToken(u.getUsername(), Map.of("amr", "pwd+backup_code"));
        return ResponseEntity.ok(resp);
    }
}
package com.example.mfa.controller;

import com.example.mfa.entity.AppUser;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.service.UserService;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
