@RestController
@RequestMapping("/me")
public class MeController {

    private final UserService userService;
    private final BackupCodeRepository backupCodeRepository;

    public MeController(UserService userService, BackupCodeRepository backupCodeRepository) {
        this.userService = userService;
        this.backupCodeRepository = backupCodeRepository;
    }

    @GetMapping
    public Map<String, Object> me(@AuthenticationPrincipal UserDetails principal) {
        AppUser u = userService.getByUsername(principal.getUsername());
        long remaining = backupCodeRepository.findByUserAndUsedFalse(u).size();
        return Map.of(
                "username", u.getUsername(),
                "mfaEnabled", u.isMfaEnabled(),
                "backupCodesRemaining", remaining
        );
    }
}
